// Topic shape: system-sensors/sensor/<id>/state
// <id> is either "netalertx" (aggregate scan stats) or "mac_xx_xx_xx_xx_xx_xx" (per-device attrs).
const parts = msg.topic.split('/');
const id = parts.length >= 3 ? parts[2] : '';

// mqtt in node uses datatype "auto-detect" — valid JSON payloads arrive already
// parsed as objects, so only re-parse if we actually got a raw string.
let payload = msg.payload;
if (typeof payload === 'string') {
    try {
        payload = JSON.parse(payload);
    } catch (e) {
        node.warn('Bad JSON on ' + msg.topic);
        return null;
    }
}

if (id === 'netalertx') {
    // Aggregate scan stats — cache for the heartbeat, no transition to log here.
    // flow-scoped: fn_heartbeat is a different node and needs to read this back.
    flow.set('agg_stats', payload);
    return null;
}

if (!id.startsWith('mac_')) {
    return null;
}

const mac = id.substring(4).replace(/_/g, ':');

// New-device detection — fire once per newly-flagged device. Clears when
// NetAlertX itself clears is_new (e.g. the device gets named/acknowledged),
// so a genuinely new appearance later can fire again.
const wasFlagged = flow.get('newflag_' + mac) === true;
const isNew = payload.is_new === '1' || payload.is_new === 1 || payload.is_new === true;

if (isNew && !wasFlagged) {
    flow.set('newflag_' + mac, true);
    const label = payload.model || payload.vendor || 'unknown device';
    return {
        payload: JSON.stringify({
            component: 'netalertx',
            category: 'Alert',
            message: 'New device detected: ' + label + ' (' + mac + ', ' + (payload.last_ip || 'no IP') + ')'
        })
    };
}

if (!isNew && wasFlagged) {
    flow.set('newflag_' + mac, false);
}

return null;

const stats = flow.get('agg_stats');
let statsText = 'no scan data yet';
if (stats) {
    statsText = stats.online + ' online, ' + stats.down + ' down, ' + stats.all + ' total' +
        (stats.new > 0 ? ', ' + stats.new + ' new' : '') +
        (stats.unknown > 0 ? ', ' + stats.unknown + ' unknown' : '');
}

const logMsg = {
    payload: JSON.stringify({
        component: 'netalertx',
        category: 'System',
        message: 'Heartbeat - ' + statsText
    })
};

const heartbeatMsg = {
    payload: JSON.stringify({
        component: 'netalertx',
        stats: stats || {}
    })
};

return [logMsg, heartbeatMsg];
